package com.google.gson.protobuf.generated;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.ExtensionRegistryLite;
import org.junit.jupiter.api.Test;

class BagTest {

  @Test
  void registerAllExtensions_withExtensionRegistryLite_doesNotThrow() {
    ExtensionRegistryLite mockRegistry = mock(ExtensionRegistryLite.class);
    assertDoesNotThrow(() -> Bag.registerAllExtensions(mockRegistry));
  }
}
